+fn truncate_with_ellipsis(input: &str, width: usize) -> String {
+    if width == 0 {
+        return String::new();
+    }
+    let char_count = input.chars().count();
+    if char_count <= width {
+        return input.to_string();
+    }
+    if width == 1 {
+        return "\u{2026}".to_string();
+    }
+    let mut out: String = input.chars().take(width - 1).collect();
+    out.push('\u{2026}');
+    out
+}
